questions.text:
What is the output of the following code?

```cpp
double u = 4.0, v = 2.0;
cout << pow(u, v) << endl;
```

Trace the output of the following code:

```cpp
int x = -25;
cout << abs(x) + 5 << endl;
```

Consider the following function definition. What will `compute(5, 3)` return?

```cpp
int compute(int a, int b) {
    if (a > b)
        return a - b;
    else
        return b - a;
}
```

What will be printed by the following code?

```cpp
int test(int x) {
    x = x + 10;
    return x;
}

int main() {
    int num = 5;
    cout << test(num) << " " << num << endl;
    return 0;
}
```

Given the following code, what is the output?

```cpp
int findVal(int n) {
    if (n <= 0) return 0;
    return n + findVal(n - 2);
}
// In main:
cout << findVal(4) << endl;
```

What is the output of the following sequence?

```cpp
int a = 10;
int b = 20;
int c = max(a, b); // Assume standard max
cout << pow(c, 0) << endl;
```

What is the output of the following code?

```cpp
int x = 10;
if (x > 5) {
    cout << "A ";
    return 0; // Assume this is inside main
    cout << "B ";
}
```
